#!/usr/bin/env node
/**
 * bundle-migrations.js - Converts drizzle-kit generated SQL files into a JS module
 * that can be imported by React Native.
 *
 * Reads drizzle-migrations/_journal.json and all referenced .sql files,
 * then writes src/framework/db/migrations/drizzleMigrations.js with the
 * journal and SQL strings as exports.
 *
 * Run after: npx drizzle-kit generate
 * Usage: node scripts/bundle-migrations.js
 */

const fs = require("fs");
const path = require("path");

const MIGRATIONS_DIR = path.join(__dirname, "..", "drizzle-migrations");
const OUTPUT_FILE = path.join(__dirname, "..", "src", "framework", "db", "migrations", "drizzleMigrations.js");

const journalPath = path.join(MIGRATIONS_DIR, "meta", "_journal.json");
if (!fs.existsSync(journalPath)) {
    console.error("No _journal.json found. Run 'npx drizzle-kit generate' first.");
    process.exit(1);
}

const journal = JSON.parse(fs.readFileSync(journalPath, "utf-8"));

const sqlFiles = {};
for (const entry of journal.entries) {
    const sqlPath = path.join(MIGRATIONS_DIR, `${entry.tag}.sql`);
    if (!fs.existsSync(sqlPath)) {
        console.error(`SQL file not found: ${sqlPath}`);
        process.exit(1);
    }
    sqlFiles[entry.tag] = fs.readFileSync(sqlPath, "utf-8");
}

const output = `/**
 * Auto-generated by scripts/bundle-migrations.js
 * Do not edit manually. Re-run after: npx drizzle-kit generate
 */

export const journal = ${JSON.stringify(journal, null, 2)};

export const sqlFiles = ${JSON.stringify(sqlFiles, null, 2)};
`;

fs.mkdirSync(path.dirname(OUTPUT_FILE), {recursive: true});
fs.writeFileSync(OUTPUT_FILE, output, "utf-8");
console.log(`Bundled ${journal.entries.length} migration(s) → ${path.relative(process.cwd(), OUTPUT_FILE)}`);
